import React, { useState } from 'react';
import TrackClip from './TrackClip';

function Track({ name, color, clips = [] , onSelect }) {
  return (
    <div className="track-row">
      <div className="track-header" style={{ background: color }}>
        <div className="track-name">{name}</div>
        <div className="track-controls">
          <button className="btn tiny">M</button>
          <button className="btn tiny">S</button>
        </div>
      </div>
      <div className="track-clip-area">
        {clips.map((c, idx) => (
          <div key={idx} onClick={() => onSelect(c)}>
            <TrackClip title={c.title} length={c.length} />
          </div>
        ))}
      </div>
    </div>
  );
}

export default function TrackList({ onSelectClip }) {
  const [selected, setSelected] = useState(null);
  const tracks = [
    { name: 'Drums', color: '#FFCDD2', clips: [{ title: 'Loop A', length: 4 }, { title: 'Fill', length: 2 }] },
    { name: 'Bass', color: '#C8E6C9', clips: [{ title: 'Bassline', length: 8 }] },
    { name: 'Keys', color: '#BBDEFB', clips: [{ title: 'Chords', length: 8 }] },
    { name: 'Lead', color: '#E1BEE7', clips: [{ title: 'Lead1', length: 6 }] }
  ];

  function handleSelect(c) {
    setSelected(c);
    onSelectClip?.(c);
  }

  return (
    <div className="tracklist">
      {tracks.map((t) => (
        <Track key={t.name} name={t.name} color={t.color} clips={t.clips} onSelect={handleSelect} />
      ))}
    </div>
  );
}
